 1	import React, { FC, useState } from 'react';
 2	import { saveAs } from 'file-saver';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { YAMLEditor } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Button, Tooltip } from '@patternfly/react-core';
 7	import { CopyIcon, DownloadIcon } from '@patternfly/react-icons';
 8	
 9	type YamlAndCLIEditorProps = {
10	  code: string;
11	  minHeight: number;
12	};
13	
14	const YamlAndCLIEditor: FC<YamlAndCLIEditorProps> = ({ code, minHeight }) => {
15	  const { t } = useKubevirtTranslation();
16	  const [copySuccess, setCopySuccess] = useState(false);
17	  const handleDownload = () => {
18	    // Download the code as a file
19	    const blob = new Blob([code], { type: 'text/plain' });
20	    saveAs(blob, 'code.txt');
21	  };
22	
23	  const handleCopy = () => {
24	    navigator.clipboard.writeText(code).then(() => {
25	      setCopySuccess(true);
26	      setTimeout(() => setCopySuccess(false), 2000);
27	    });
28	  };
29	  return (
30	    <YAMLEditor
31	      toolbarLinks={[
32	        <Tooltip content={t('Download')} key="download">
33	          <Button onClick={handleDownload} variant="secondary">
34	            <DownloadIcon />
35	          </Button>
36	        </Tooltip>,
37	        <Tooltip
38	          content={copySuccess ? t('Successfully copied to clipboard!') : t('Copy to clipboard')}
39	          key="copy"
40	        >
41	          <Button onClick={handleCopy} variant="secondary">
42	            <CopyIcon />
43	          </Button>
44	        </Tooltip>,
45	      ]}
46	      minHeight={minHeight}
47	      options={{ readOnly: true }}
48	      showShortcuts
49	      value={code}
50	    />
51	  );
52	};
53	
54	export default YamlAndCLIEditor;

